import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const d3Container = useRef(null);

    useEffect(() => {
        let svg;
        let width = d3Container.current.clientWidth;
        let height = d3Container.current.clientHeight;
        let margin = { top: 30, right: 20, bottom: 30, left: 50 };
        let chartW = width - margin.left - margin.right;
        let chartH = height - margin.top - margin.bottom;
        d3.select(d3Container.current).selectAll('*').remove();
        Promise.all([
            axios.get('http://localhost:3001/api/uastl'),
            d3.csv('/CoolWarmFloat257.csv', d => ({
                scalar: +d.Scalar,
                color: d3.rgb(+d.R * 255, +d.G * 255, +d.B * 255).formatHex()
            }))
        ]).then(([res, cmapData]) => {
            let data = res.data;
            if (!data || data.length === 0) return;
            if (range && range.length === 2) data = data.slice(range[0], range[1] + 1);
            const keys = Object.keys(data[0]);
            const n = data.length;
            const seasonalKeys = keys.filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const L = seasonalKeys.length;
            const titles = ['input data', 'trend component', ...seasonalKeys.map((k, i) => `seasonal component ${i + 1}`), 'residual component'];
            const meanKeys = ['input_mean', 'trend_mean', ...seasonalKeys, 'residual_mean'];
            const stdKeys = ['input_std', 'trend_std', ...seasonalKeys.map(k => k.replace('_mean', '_std')), 'residual_std'];
            const corrKeys = ['corr_input', 'corr_trend', ...seasonalKeys.map(k => k.replace('_mean', '')), 'corr_residual'];
            const sampleKeys = [1, 2, 3].map(i => [
                `sample${i}_input`, `sample${i}_trend`, ...seasonalKeys.map((k, idx) => `sample${i}_seasonal${idx + 1}`), `sample${i}_residual`
            ]);
            const subplotH = chartH / meanKeys.length;
            // colormap
            const coolwarm = d3.scaleLinear()
                .domain([-1, 0, 1])
                .range([
                    cmapData[0].color,
                    cmapData[Math.floor(cmapData.length / 2)].color,
                    cmapData[cmapData.length - 1].color
                ]);
            // 顏色設計
            const mainColor = '#1a237e'; // 深藍
            const bandColor99 = '#90caf9'; // 99%區間
            const bandColor50 = '#64b5f6'; // 50%區間
            const sampleColors = ['#ff9800', '#ffd600', '#8e24aa']; // 橘、黃、紫
            const meanLineWidth = 1.5;
            const fontFamily = 'Arial';
            svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height)
                .style('background', 'none');
            meanKeys.forEach((key, i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left},${margin.top + i * subplotH})`);
                const vals = data.map(d => +d[key]);
                const stds = data.map(d => +d[stdKeys[i]]);
                const y = d3.scaleLinear()
                    .domain([d3.min(vals, (d, j) => d - 2.6 * stds[j]), d3.max(vals, (d, j) => d + 2.6 * stds[j])]).nice()
                    .range([subplotH - 32, 0]);
                const x = d3.scaleLinear()
                    .domain([0, n - 1])
                    .range([0, chartW]);
                // 信賴區間（99%）
                g.append('path')
                    .datum(vals.map((m, j) => ({ x: x(j), y0: y(m - 2.57 * stds[j]), y1: y(m + 2.57 * stds[j]) })))
                    .attr('fill', bandColor99)
                    .attr('opacity', 0.25)
                    .attr('d', d3.area()
                        .x(d => d.x)
                        .y0(d => d.y0)
                        .y1(d => d.y1)
                    );
                // 信賴區間（50%）
                g.append('path')
                    .datum(vals.map((m, j) => ({ x: x(j), y0: y(m - 0.67 * stds[j]), y1: y(m + 0.67 * stds[j]) })))
                    .attr('fill', bandColor50)
                    .attr('opacity', 0.35)
                    .attr('d', d3.area()
                        .x(d => d.x)
                        .y0(d => d.y0)
                        .y1(d => d.y1)
                    );
                // 樣本路徑
                sampleKeys.forEach((sks, si) => {
                    const sample = data.map(d => +d[sks[i]]);
                    g.append('path')
                        .datum(sample)
                        .attr('fill', 'none')
                        .attr('stroke', sampleColors[si % sampleColors.length])
                        .attr('stroke-width', 1)
                        .attr('opacity', 0.7)
                        .attr('d', d3.line()
                            .x((d, idx) => x(idx))
                            .y(d => y(d))
                        );
                });
                // 均值線
                g.append('path')
                    .datum(vals)
                    .attr('fill', 'none')
                    .attr('stroke', mainColor)
                    .attr('stroke-width', meanLineWidth)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                    );
                // 底部紅藍正弦波條
                const corr = data.map(d => +d[corrKeys[i]]);
                const barY = subplotH - 28;
                const barH = 12;
                const sine = d3.range(n).map(idx => Math.sin(idx / n * 2 * Math.PI * 3));
                // 紅藍條（正弦波高度+colormap）
                let pathStr = '';
                for (let idx = 0; idx < n - 1; idx++) {
                    const x0 = x(idx), x1 = x(idx + 1);
                    const y0 = barY + barH / 2 - sine[idx] * barH / 2;
                    const y1 = barY + barH / 2 - sine[idx + 1] * barH / 2;
                    pathStr += `M${x0},${barY + barH / 2}L${x0},${y0}L${x1},${y1}L${x1},${barY + barH / 2}Z`;
                    g.append('path')
                        .attr('d', `M${x0},${barY + barH / 2}L${x0},${y0}L${x1},${y1}L${x1},${barY + barH / 2}Z`)
                        .attr('fill', coolwarm((corr[idx] + corr[idx + 1]) / 2))
                        .attr('opacity', 0.95);
                }
                // 標題
                g.append('text')
                    .attr('x', chartW / 2)
                    .attr('y', -8)
                    .attr('fill', mainColor)
                    .attr('font-size', 18)
                    .attr('font-family', fontFamily)
                    .attr('font-weight', 'bold')
                    .attr('text-anchor', 'middle')
                    .text(titles[i]);
                // Y軸
                g.append('g')
                    .call(d3.axisLeft(y).ticks(4))
                    .selectAll('text').attr('fill', mainColor).attr('font-family', fontFamily);
                // X軸（只畫在最後一個子圖）
                if (i === meanKeys.length - 1) {
                    g.append('g')
                        .attr('transform', `translate(0,${subplotH - 32})`)
                        .call(d3.axisBottom(x).ticks(10).tickFormat(idx => idx))
                        .selectAll('text').attr('fill', mainColor).attr('font-family', fontFamily);
                }
            });
        });
    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', background: 'none' }}>
            <div ref={d3Container} style={{ width: '100%', height: '500px', borderRadius: '12px', overflow: 'hidden', position: 'relative' }} />
        </div>
    );
}

export default UASTLChart;
